#include <iostream>

class Guard {
    int value_;
    static int live_;
public:
    explicit Guard(int value) : value_(value) { ++live_; }
    ~Guard() { --live_; }
    int value() const { return value_; }
    static int live() { return live_; }
};
int Guard::live_ = 0;

int main() {
    int value{};
    if (!(std::cin >> value)) return 1;
    { Guard guard(value); std::cout << Guard::live() << ' ' << guard.value() << '\n'; }
    std::cout << Guard::live() << '\n';
}
